#include <iostream>
using namespace std;
int a[1000005],n,r;
int main()
{
    cin>>n>>r;
    for(int i=(1<<n)-1;i>=0;i--)
    {
        int count=0;
        for(int j=0;j<=n-1;j++)
        {
            if(i&(1<<j))
            {
                a[count]=j;
                count++;
            }
        }
        if(count==r)
        {
            for(int j=count-1;j>=0;j--)
            {
                printf("%3d",n-a[j]);
            }
            cout<<endl;
        }
    }
    return 0;
}
